CREATE TABLE appInfo(appInfoId INTEGER PRIMARY KEY AUTOINCREMENT,appInfoName TEXT NOT NULL DEFAULT "",appInfoVersion TEXT NOT NULL DEFAULT 0,appInfoSchemaVersion INTEGER NOT NULL DEFAULT 0,appInfoLastUpdate DATETIME DEFAULT CURRENT_TIMESTAMP,appInfoFirstLaunch INTEGER NOT NULL DEFAULT 0,appInfoTheme INTEGER NOT NULL DEFAULT 0,appInfoInstallDate DATETIME DEFAULT CURRENT_TIMESTAMP,appErrorStamp DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE appErrors(appErrorId INTEGER PRIMARY KEY AUTOINCREMENT,appErrorCode TEXT NOT NULL,appErrorType INTEGER NOT NULL,appErrorText TEXT NOT NULL,appErrorStamp DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX idx_appErrorType ON appErrors(appErrorType);
CREATE TABLE appErrorTypes(appErrorTypeId INTEGER PRIMARY KEY AUTOINCREMENT,appErrorTypeName TEXT NOT NULL,appErrorTypeStamp DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE appUsers(appUserID INTEGER PRIMARY KEY AUTOINCREMENT,appUserType INTEGER NOT NULL DEFAULT 0,appUserFullName TEXT NOT NULL DEFAULT "",appUserCompany TEXT NOT NULL DEFAULT "",appUserVendorName TEXT NOT NULL DEFAULT "",appUserEmail TEXT NOT NULL DEFAULT "",appUserPassword TEXT NOT NULL DEFAULT "",appUserCountry INTEGER NOT NULL DEFAULT 0,appUserTerms INTEGER NOT NULL DEFAULT 0,appUserLic INTEGER NOT NULL DEFAULT 0,appUserActive INTEGER NOT NULL DEFAULT 1,appUserStamp DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX idx_appUserType ON appUsers(appUserType);
CREATE INDEX idx_appUserCountry ON appUsers(appUserCountry);
CREATE INDEX idx_appUserTerms ON appUsers(appUserTerms);
CREATE INDEX idx_appUserLic ON appUsers(appUserLic);
CREATE INDEX idx_appUserActive ON appUsers(appUserActive);
CREATE TABLE appUserTypes(appUserTypeId INTEGER PRIMARY KEY AUTOINCREMENT,appUserTypeName TEXT NOT NULL,appUserTypeStamp DATETIME DEFAULT CURRENT_TIMESTAMP);
